using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
public class Script {
    public static object Main() {
        var controllers = Object.FindObjectsOfType<AnimalController>();
        foreach (var c in controllers) {
            var sd = c.StateData;
            if (sd == null || sd.EntityId != 17) continue;
            return $"Dog17 State={sd.AnimalState} FollowTarget={sd.FollowTargetId} Speed={sd.MoveSpeed:F2}";
        }
        return "Dog17 not found";
    }
}
